const text = $input.item.json.text || '';
const widthInches = parseInt($input.item.json.width) || 24;
const color = ($input.item.json.color || 'red').toLowerCase();

// Convert to feet for display
const widthFeet = Math.round(widthInches / 12);

// Base price: $5 per inch + $3 per character
const basePrice = widthInches * 5;
const complexityPrice = text.length * 3;

const colorMultipliers = {
  'red': 1.0,
  'blue': 1.0,
  'green': 1.0,
  'pink': 1.1,
  'white': 1.15,
  'warm white': 1.2,
  'rgb': 1.3,
  'rainbow': 1.3
};

const colorMultiplier = colorMultipliers[color] || 1.0;
const totalPrice = (basePrice + complexityPrice) * colorMultiplier;
const minPrice = Math.round(totalPrice * 0.9);
const maxPrice = Math.round(totalPrice * 1.1);

const colorName = color.charAt(0).toUpperCase() + color.slice(1);

return {
  json: {
    price_range: `$${minPrice} - $${maxPrice}`,
    details: `Text: "${text}", Size: ${widthFeet} feet, Color: ${colorName}`,
    price_min: minPrice,
    price_max: maxPrice
  }
};
